tContent.trim() : '', institution: institutions.join(', '), bio: bio.substring(0, 500), avatar: avatarEl ? avatarEl.getAttribute('src') : '', learners: learnersMatch ? learnersMatch[0] : '', rating: ratingEl ? (ratingEl.getAttribute('aria-label') || ratingEl.textContent.trim()) : '', course_count: coursesCountMatch ? coursesCountMatch[1] : String(courses.length), courses: courses, profile_url: window.location.href }`)

